import{c as o,Q as a,j as t,m as d}from"./chunks/framework.rlpw0eGz.js";const h=JSON.parse('{"title":"微信小程序登录逻辑","description":"","frontmatter":{},"headers":[],"relativePath":"web/uniapp/微信小程序登录逻辑.md","filePath":"web/uniapp/微信小程序登录逻辑.md","lastUpdated":null}'),r={name:"web/uniapp/微信小程序登录逻辑.md"};function n(c,e,p,i,s,l){return a(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="微信小程序登录逻辑" tabindex="-1">微信小程序登录逻辑 <a class="header-anchor" href="#微信小程序登录逻辑" aria-label="Permalink to &quot;微信小程序登录逻辑&quot;">​</a></h1><h2 id="系统登录" tabindex="-1">系统登录 <a class="header-anchor" href="#系统登录" aria-label="Permalink to &quot;系统登录&quot;">​</a></h2><p>小程序发起请求获取当前用户的 <code>code</code> （通过 <code>wx.login</code> 接口获得临时登录凭证 <code>code</code> ）</p><p>将 <code>code</code> 发送到后台服务进行登录逻辑。</p><p>后台接受到请求后判断用户是否登录，若已登录，则直接返回<code>token</code>。</p><p>未登录则用<code>code</code> 取 <code>openid</code> ( <a href="https://developers.weixin.qq.com/miniprogram/dev/api-backend/open-api/login/auth.code2Session.html" target="_blank" rel="noreferrer">auth.code2Session</a> ), 用获取的<code>openid</code>在系统中查询是否存在用户。</p><p>存在则用该用户登录，不存在则创建新用户并登录，然后返回 <code>token</code>。</p><p>小程序收到登录 <code>token</code> 视为系统登录成功。</p><h2 id="同步微信用户信息" tabindex="-1">同步微信用户信息 <a class="header-anchor" href="#同步微信用户信息" aria-label="Permalink to &quot;同步微信用户信息&quot;">​</a></h2><p>小程序收到 <code>token</code> 后，向微信请求用户信息 ( <a href="https://developers.weixin.qq.com/miniprogram/dev/api/open-api/user-info/wx.getUserInfo.html" target="_blank" rel="noreferrer">wx.getUserInfo(Object object)</a> ) 。</p><p>小程序将获取到的用户信息传输给后台，将后台用户信息进行保存。</p><p>结束登录。</p>',12)])])}const m=o(r,[["render",n]]);export{h as __pageData,m as default};
